flow.set('id_log_no', 0);
flow.set('id_rx_count', 0);
flow.set('filtered_no', 0);
flow.set('link_costs', {});
flow.set('link_order', []);
flow.set('challenge_done', false);
flow.set('thingspeak_started', false);
flow.set('generator_enabled', false);

return [
    { payload: 'No.,ID,TIMESTAMP\n' },
    { payload: 'No.,Timestamp,Sequence Number, Attribute,Status,Data Type,Data Value\n' },
    { payload: 'No.,Source,Destination,Cost\n' },
    { payload: 'Challenge 3 state reset. Generator is stopped.' }
];

const enabled = msg.payload === true;
flow.set('generator_enabled', enabled);
msg.payload = enabled ? 'Generator started' : 'Generator stopped';
return msg;

if (!flow.get('generator_enabled')) {
    return null;
}

if (flow.get('challenge_done')) {
    flow.set('generator_enabled', false);
    node.status({ fill: 'green', shape: 'ring', text: 'stopped after 200 received IDs' });
    return null;
}

const id = Math.floor(Math.random() * 30001);
const timestamp = Math.floor(Date.now() / 1000);
const no = (flow.get('id_log_no') || 0) + 1;
flow.set('id_log_no', no);
node.status({ fill: 'blue', shape: 'dot', text: `generated ${no}` });

const mqttMsg = {
    topic: 'challenge3/id_generator',
    payload: JSON.stringify({ id, timestamp })
};

const csvMsg = {
    payload: `${no},${id},${timestamp}\n`
};

return [mqttMsg, csvMsg];

if (flow.get('challenge_done')) {
    return null;
}

let payload = msg.payload;
if (typeof payload === 'string') {
    payload = JSON.parse(payload);
}

const id = Number(payload.id);
if (!Number.isFinite(id)) {
    node.error('Invalid ID payload', msg);
    return null;
}

const count = (flow.get('id_rx_count') || 0) + 1;
flow.set('id_rx_count', count);

msg.sub_id = id;
msg.sub_timestamp = payload.timestamp;
msg.id_rx_count = count;
msg.N = id % 5218;

if (count >= 200) {
    flow.set('challenge_done', true);
}

return msg;

let row = null;

if (Array.isArray(msg.payload)) {
    row = msg.payload.find(r => Number(r['Packet Number']) === Number(msg.N));
} else if (msg.payload && typeof msg.payload === 'object') {
    if (Number(msg.payload['Packet Number']) !== Number(msg.N)) {
        return null;
    }
    row = msg.payload;
} else {
    node.error('Unexpected CSV payload format', msg);
    return null;
}

if (!row) {
    node.warn(`No CSV row found for Packet Number ${msg.N}`);
    return null;
}

msg.csvRow = row;
msg.commandString = row['Command String'] || '';

const isZcl = msg.commandString.includes('ZBEE_ZCL');
const isLinkStatus = row['Packet Type'] === 'Link Status (0x08)';

let doneMsg = null;
if (flow.get('challenge_done') && !flow.get('thingspeak_started')) {
    flow.set('thingspeak_started', true);
    doneMsg = { payload: '200 ID messages processed' };
}

if (isZcl) {
    return [msg, null, doneMsg, null];
}
if (isLinkStatus) {
    return [null, msg, doneMsg, null];
}
return [null, null, doneMsg, msg];

const row = msg.csvRow;
const rawDev = row['Device Name ZigBee Source'];
const dev = String(rawDev || '').trim().replace(/[#+\u0000]/g, '_');

if (!dev) {
    node.warn('Missing Device Name ZigBee Source, skipping ZBEE_ZCL publish');
    return null;
}

const topic = 'ZigBee/' + dev;
const currentTimestamp = Math.floor(Date.now() / 1000);

msg.topic = topic;
msg.currentTimestamp = currentTimestamp;
msg.payload = JSON.stringify({
    timestamp: currentTimestamp,
    id: msg.sub_id,
    'wpan.src': row['Source Address'],
    'wpan.dst': row['Destination Address'],
    'zbee.src': row['Source Address ZigBee'],
    'zbee.dst': row['Destination Address ZigBee'],
    topic: topic,
    payload: row['Command String']
});

return msg;

function parseCommandString(text) {
    try {
        return JSON.parse(String(text || '').replace(/'/g, '"'));
    } catch (err) {
        node.warn('Cannot parse Command String: ' + err.message);
        return null;
    }
}

function asArray(value) {
    if (Array.isArray(value)) return value;
    if (value === undefined || value === null || value === '') return [];
    return [value];
}

function cleanLabel(value) {
    return String(value || '').replace(/\s*\([^)]*\)/g, '').trim();
}

function valueKeyForType(dataType) {
    const t = String(dataType || '').toLowerCase();
    if (t.includes('16-bit signed integer')) return 'Int16';
    if (t.includes('16-bit unsigned integer')) return 'Uint16';
    if (t.includes('8-bit signed integer')) return 'Int8';
    if (t.includes('8-bit unsigned integer')) return 'Uint8';
    if (t.includes('32-bit signed integer')) return 'Int32';
    if (t.includes('32-bit unsigned integer')) return 'Uint32';
    if (t.includes('48-bit unsigned integer')) return 'Uint48';
    return null;
}

function rawValueAt(command, dataTypes, index) {
    const key = valueKeyForType(dataTypes[index]);
    if (!key || command[key] === undefined || command[key] === null) return null;

    const values = command[key];
    const sameTypeIndex = dataTypes.slice(0, index + 1)
        .filter(dt => valueKeyForType(dt) === key).length - 1;

    if (Array.isArray(values)) return values[sameTypeIndex] !== undefined ? values[sameTypeIndex] : null;
    return sameTypeIndex === 0 ? values : null;
}

function cleanValue(value) {
    const text = String(value || '').trim();
    const match = text.match(/^-?\d+(?:\.\d+)?/);
    return match ? match[0] : text;
}

const command = parseCommandString(msg.csvRow && msg.csvRow['Command String']);
if (!command) return null;

const attrs = asArray(command.Attribute);
const statuses = asArray(command.Status);
const dataTypes = asArray(command['Data Type']);
const wanted = ['Active Power', 'RMS Current', 'RMS Voltage'];
const timestamp = msg.currentTimestamp || Math.floor(Date.now() / 1000);
const seq = command['Sequence Number'];

const csvMsgs = [];
const currentMsgs = [];
const voltageMsgs = [];

for (let i = 0; i < attrs.length; i++) {
    const attr = cleanLabel(attrs[i]);
    if (!wanted.includes(attr)) continue;

    const statusRaw = statuses[i];
    const dataTypeRaw = dataTypes[i];
    const valueRaw = rawValueAt(command, dataTypes, i);

    if (statusRaw === undefined || dataTypeRaw === undefined || valueRaw === null) {
        continue;
    }

    const no = (flow.get('filtered_no') || 0) + 1;
    flow.set('filtered_no', no);

    const status = cleanLabel(statusRaw);
    const dataType = cleanLabel(dataTypeRaw);
    const value = cleanValue(valueRaw);
    const csvLine = no + ',' + timestamp + ',' + seq + ',' + attr + ',' + status + ',' + dataType + ',' + value + '\n';
    csvMsgs.push({ payload: csvLine });

    const numericValue = Number(value);
    if (Number.isFinite(numericValue) && attr === 'RMS Current') {
        currentMsgs.push({ payload: numericValue, topic: 'RMS Current' });
    }
    if (Number.isFinite(numericValue) && attr === 'RMS Voltage') {
        voltageMsgs.push({ payload: numericValue, topic: 'RMS Voltage' });
    }
}

if (csvMsgs.length || currentMsgs.length || voltageMsgs.length) {
    node.send([
        csvMsgs.length ? csvMsgs : null,
        currentMsgs.length ? currentMsgs : null,
        voltageMsgs.length ? voltageMsgs : null
    ]);
}

return null;

function parseCommandString(text) {
    try {
        return JSON.parse(String(text || '').replace(/'/g, '"'));
    } catch (err) {
        node.warn('Cannot parse Link Status Command String: ' + err.message);
        return null;
    }
}

const row = msg.csvRow;
const command = parseCommandString(row && row['Command String']);
if (!command || !Array.isArray(command.Links)) return null;

const source = row['Source Address ZigBee'];
if (!source) return null;

const costs = flow.get('link_costs') || {};
const order = flow.get('link_order') || [];

for (const link of command.Links) {
    const destination = link.Address;
    const cost = link['Outgoing Cost'];
    if (!destination || cost === undefined || cost === null) continue;

    const key = source + '|' + destination;
    if (!costs[key]) {
        order.push({ source: source, destination: destination });
    }
    costs[key] = { source: source, destination: destination, cost: String(cost) };
}

flow.set('link_costs', costs);
flow.set('link_order', order);

let csv = 'No.,Source,Destination,Cost\n';
let no = 1;
for (const item of order) {
    const key = item.source + '|' + item.destination;
    const current = costs[key];
    if (!current) continue;
    csv += no + ',' + current.source + ',' + current.destination + ',' + current.cost + '\n';
    no += 1;
}

return { payload: csv };

const WRITE_API_KEY = env.get('THINGSPEAK_WRITE_API_KEY');

if (!WRITE_API_KEY) {
    node.warn('THINGSPEAK_WRITE_API_KEY is not configured; skipping HTTP updates');
    return null;
}

const costs = flow.get('link_costs') || {};
const order = flow.get('link_order') || [];
const sources = Array.from(new Set(order.map(item => item.source)));

if (sources.length === 0) {
    node.warn('No outgoing costs available for ThingSpeak');
    return null;
}

sources.sort((a, b) => parseInt(a, 16) - parseInt(b, 16));
const minSource = sources[0];
const destinations = order
    .filter(item => item.source === minSource)
    .map(item => item.destination)
    .filter((value, index, arr) => arr.indexOf(value) === index)
    .sort((a, b) => parseInt(a, 16) - parseInt(b, 16));

for (const destination of destinations) {
    const key = minSource + '|' + destination;
    const item = costs[key];
    if (!item) continue;

    node.send({
        url: 'https://api.thingspeak.com/update?api_key=' + WRITE_API_KEY + '&field1=' + encodeURIComponent(item.cost),
        payload: item.cost,
        source: minSource,
        destination: destination
    });
}

return null;
